(window["webpackJsonp"]=window["webpackJsonp"]||[]).push([["home39"],{"914c":function(n,e){n.exports="### 范例\n查询商品列表数据\n```js\nrouter.get(\"/list\", function (req, res, next) {\n  // 获取当前页 page\n  let page = parseInt(req.param(\"page\"));\n  // 获取每页条数 pageSize\n  let pageSize = parseInt(req.param(\"pageSize\"));\n  // 获取价格等级priceLevel\n  let priceLevel = req.param(\"priceLevel\");\n  //  获取排序sort\n  let sort = req.param(\"sort\");\n  //  算出当前页要跳过多少条数据\n  let skip = (page - 1) * pageSize;\n  // 根据priceLevel获取价格区间\n  var priceGt = '',  \n    priceLte = '';  \n  let params = {};\n  if (priceLevel != 'all') {\n    switch (priceLevel) {\n      case '0':\n        priceGt = 0;\n        priceLte = 100;\n        break;\n      case '1':\n        priceGt = 100;\n        priceLte = 500;\n        break;\n      case '2':\n        priceGt = 500;\n        priceLte = 1000;\n        break;\n      case '3':\n        priceGt = 1000;\n        priceLte = 5000;\n        break;\n    }\n    // 设置查询价格参数\n    params = {\n      salePrice: {\n        $gt: priceGt,\n        $lte: priceLte\n      }\n    }\n  }\n  // 查询sql\n  let goodsModel = Goods.find(params).skip(skip).limit(pageSize);\n  // 排序\n  goodsModel.sort({\n    'salePrice': sort\n  });\n  // 获取数据\n  goodsModel.exec(function (err, doc) {\n    if (err) {\n      res.json({\n        status: '1',\n        msg: err.message\n      });\n    } else {\n      res.json({\n        status: '0',\n        msg: '',\n        result: {\n          count: doc.length,\n          list: doc\n        }\n      });\n    }\n  })\n});\n```\n加入到购物车\n```js\nrouter.post(\"/addCart\", function (req, res, next) {\n  // 从cookie获取用户的 id\n  const userId = req.cookies.userId;\n  // 获取产品id\n  const productId = req.body.productId;\n  // 获取user的 model\n  const User = require('../models/user');\n\n  // 获取用户信息\n  User.findOne({\n    userId: userId\n  }, function (err, userDoc) {\n    if (err) {  // 获取失败\n      res.json({\n        status: \"1\",\n        msg: err.message\n      })\n    } else { // 获取成功\n      // 用户信息存在\n      if (userDoc) {\n        // 该产品是否在购物车中，在购物车中的话 ,productNum++\n        var goodsItem = '';\n        userDoc.cartList.forEach(function (item) {\n          if (item.productId == productId) {\n            goodsItem = item;\n            item.productNum++;\n          }\n        });\n        // 在购物车中\n        if (goodsItem) {\n          userDoc.save(function (err2, doc2) {\n            if (err2) {\n              res.json({\n                status: \"1\",\n                msg: err2.message\n              })\n            } else {\n              res.json({\n                status: '0',\n                msg: '',\n                result: 'suc'\n              })\n            }\n          })\n        // 不在购物车中\n        } else {\n          // 获取该产品的信息\n          Goods.findOne({\n            productId: productId\n          }, function (err1, doc) {\n            // 获取失败\n            if (err1) {\n              res.json({\n                status: \"1\",\n                msg: err1.message\n              })\n            // 获取成功\n            } else {\n              if (doc) {\n                //将该产品添加到购物车userDoc.cartList中\n                userDoc.cartList.push({\n                  \"productId\": doc.productId,\n                  \"productName\": doc.productName,\n                  \"salePrice\": doc.salePrice,\n                  \"productImage\": doc.productImage,\n                  \"productNum\": 1,\n                  \"checked\": 1\n                });\n                // 保存userDoc\n                userDoc.save(function (err2, doc2) {\n                  // 保存成功\n                  if (err2) {\n                    res.json({\n                      status: \"1\",\n                      msg: err2.message\n                    })\n                  // 保存失败\n                  } else {\n                    res.json({\n                      status: '0',\n                      msg: '',\n                      result: 'suc'\n                    })\n                  }\n                })\n              }\n            }\n          });\n        }\n      // 用户信息不存在\n      }else{ \n        res.json({\n          status: \"1\",\n          msg: '用户信息不存在'\n        })\n      }\n    }\n  })\n});\n```\n\n用户登录\n```js\nrouter.post(\"/login\", function (req, res, next) {\n  // 获取用户名和密码\n  var param = {\n    userName: req.body.userName,\n    userPwd: req.body.userPwd\n  }\n  // 查询是否存在改用户\n  User.findOne(param, function (err, doc) {\n    // 不存在\n    if (err) {\n      res.json({\n        status: \"1\",\n        msg: err.message\n      });\n    // 存在\n    } else {\n      if (doc) {\n        // 将userId 写入到cookie里\n        res.cookie(\"userId\", doc.userId, {\n          path: '/',\n          maxAge: 1000 * 60 * 60\n        });\n        // 将userName 写入到cookie里\n        res.cookie(\"userName\", doc.userName, {\n          path: '/',\n          maxAge: 1000 * 60 * 60\n        });\n        //req.session.user = doc;\n        // 登录成功\n        res.json({\n          status: '0',\n          msg: '',\n          result: {\n            userName: doc.userName\n          }\n        });\n      } else {\n        // 登录失败\n        res.json({\n          status: '1',\n          msg: '账户密码错误',\n          result: ''\n        });\n      }\n    }\n  });\n});\n```\n\n是否登录\n```js\nrouter.get(\"/checkLogin\", function (req, res, next) {\n  if (req.cookies.userId) {\n    res.json({\n      status: '0',\n      msg: '',\n      result: req.cookies.userName || ''\n    });\n  } else {\n    res.json({\n      status: '1',\n      msg: '未登录',\n      result: ''\n    });\n  }\n});\n```\n\n登出接口\n```js\nrouter.post(\"/logout\", function (req, res, next) {\n  // 清除cookie\n  res.cookie(\"userId\", \"\", {\n    path: \"/\",\n    maxAge: -1\n  });\n  res.json({\n    status: \"0\",\n    msg: '',\n    result: ''\n  })\n});\n```\n登录拦截\n```js\napp.use(function (req, res, next) {\n  if (req.cookies.userId ||req.originalUrl == '/users/login' || req.originalUrl == '/users/logout' || req.path ==\"/goods/list\") {\n    next();\n  } else {\n      res.json({\n        status: '10001',\n        msg: '当前未登录',\n        result: ''\n      });\n    }\n  }\n});\n```\n\n查询当前用户的购物车数据\n```js\nrouter.get(\"/cartList\", function (req, res, next) {\n  var userId = req.cookies.userId;\n  User.findOne({\n    userId: userId\n  }, function (err, doc) {\n    if (err) {\n      res.json({\n        status: '1',\n        msg: err.message,\n        result: ''\n      });\n    } else {\n      if (doc) {\n        res.json({\n          status: '0',\n          msg: '',\n          result: doc.cartList\n        });\n      }\n    }\n  });\n});\n```\n\n购物车删除\n```js\nrouter.post(\"/cartDel\", function (req, res, next) {\n  var userId = req.cookies.userId,\n    productId = req.body.productId;\n  User.update({\n    userId: userId\n  }, {\n    $pull: {\n      'cartList': {\n        'productId': productId\n      }\n    }\n  }, function (err, doc) {\n    if (err) {\n      res.json({\n        status: '1',\n        msg: err.message,\n        result: ''\n      });\n    } else {\n      res.json({\n        status: '0',\n        msg: '',\n        result: 'suc'\n      });\n    }\n  });\n});\n```\n修改商品数量\n```js\nrouter.post(\"/cartEdit\", function (req, res, next) {\n  var userId = req.cookies.userId,\n    productId = req.body.productId,\n    productNum = req.body.productNum,\n    checked = req.body.checked;\n  User.update({\n    \"userId\": userId,\n    \"cartList.productId\": productId\n  }, {\n    \"cartList.$.productNum\": productNum,\n    \"cartList.$.checked\": checked,\n  }, function (err, doc) {\n    if (err) {\n      res.json({\n        status: '1',\n        msg: err.message,\n        result: ''\n      });\n    } else {\n      res.json({\n        status: '0',\n        msg: '',\n        result: 'suc'\n      });\n    }\n  })\n});\n```\n\n购物车全选\n```js\nrouter.post(\"/editCheckAll\", function (req, res, next) {\n  var userId = req.cookies.userId,\n    checkAll = req.body.checkAll ? '1' : '0';\n  User.findOne({\n    userId: userId\n  }, function (err, user) {\n    if (err) {\n      res.json({\n        status: '1',\n        msg: err.message,\n        result: ''\n      });\n    } else {\n      if (user) {\n        user.cartList.forEach((item) => {\n          item.checked = checkAll;\n        })\n        user.save(function (err1, doc) {\n          if (err1) {\n            res.json({\n              status: '1',\n              msg: err1.message,\n              result: ''\n            });\n          } else {\n            res.json({\n              status: '0',\n              msg: '',\n              result: 'suc'\n            });\n          }\n        })\n      }\n    }\n  });\n});\n```"},"9ef0":function(n,e,s){"use strict";s.r(e);var r=function(){var n=this,e=n.$createElement,r=n._self._c||e;return r("markdown",{attrs:{source:s("914c")}})},t=[],o=s("2877"),u={},c=Object(o["a"])(u,r,t,!1,null,null,null);e["default"]=c.exports}}]);